namespace sv_36ffe226a55f4849a1255ee629365aef.Services;

/// <summary>
/// Scoped (per-circuit) state that tracks the currently selected warehouse.
/// </summary>
public sealed class WarehouseState
{
    public static readonly (string Id, string Name)[] AvailableWarehouses =
    [
        ("WH-001", "Warehouse A – East"),
        ("WH-002", "Warehouse B – West"),
        ("WH-003", "Warehouse C – North"),
        ("WH-004", "Warehouse D – South"),
    ];

    private string _currentWarehouseId = AvailableWarehouses[0].Id;

    public string CurrentWarehouseId => _currentWarehouseId;

    public string CurrentWarehouseName =>
        Array.Find(AvailableWarehouses, w => w.Id == _currentWarehouseId).Name
        ?? _currentWarehouseId;

    public event Action? OnChange;

    public void SetWarehouse(string warehouseId)
    {
        if (_currentWarehouseId == warehouseId) return;
        _currentWarehouseId = warehouseId;
        OnChange?.Invoke();
    }
}

namespace sv_36ffe226a55f4849a1255ee629365aef.Services;

/// <summary>
/// Simulates a database query returning low-stock item counts.
/// </summary>
public sealed class InventoryAlertService
{
    private readonly Random _random = new();

    public Task<int> GetLowStockCountAsync(string warehouseId)
    {
        // Simulate async DB call with a random result per warehouse.
        int count = _random.Next(0, 16);
        return Task.FromResult(count);
    }
}

namespace sv_36ffe226a55f4849a1255ee629365aef.Services;

/// <summary>
/// Scoped pub/sub service that lets any component broadcast a new alert count
/// so all subscribers (sidebar badge, dashboard, etc.) update together.
/// </summary>
public sealed class AlertNotificationService
{
    public int LatestCount { get; private set; }

    public event Func<Task>? OnAlertCountChanged;

    public async Task PublishAsync(int newCount)
    {
        LatestCount = newCount;
        if (OnAlertCountChanged is not null)
            await OnAlertCountChanged.Invoke();
    }
}

