@using sv_36ffe226a55f4849a1255ee629365aef.Services
@rendermode InteractiveServer
@implements IDisposable
@inject WarehouseState WarehouseState
@inject InventoryAlertService InventoryService
@inject AlertNotificationService Alerts

<PageTitle>Dashboard – @WarehouseState.CurrentWarehouseName</PageTitle>

<h1>Warehouse Dashboard</h1>

<div class="card mb-4" style="max-width: 30rem;">
    <div class="card-body">
        <h5 class="card-title">@WarehouseState.CurrentWarehouseName</h5>
        <p class="card-text">
            Low-stock items:
            <span class="badge @(_lowStockCount > 0 ? "bg-danger" : "bg-success") fs-6">
                @_lowStockCount
            </span>
        </p>
        <p class="text-muted small mb-0">
            Polling every 10 s · Last checked: @_lastChecked.ToString("T")
        </p>
    </div>
</div>

@code {
    private int _lowStockCount;
    private DateTime _lastChecked = DateTime.Now;
    private Timer? _timer;

    protected override void OnInitialized()
    {
        WarehouseState.OnChange += OnWarehouseChanged;
        Alerts.OnAlertCountChanged += OnAlertCountChanged;
    }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            // Initial fetch + start polling
            await PollAlerts();
            _timer = new Timer(async _ =>
            {
                await PollAlerts();
            }, null, TimeSpan.FromSeconds(10), TimeSpan.FromSeconds(10));
        }
    }

    private async Task PollAlerts()
    {
        var count = await InventoryService.GetLowStockCountAsync(WarehouseState.CurrentWarehouseId);
        _lastChecked = DateTime.Now;
        // Publish so every subscriber (sidebar badge, etc.) updates.
        await Alerts.PublishAsync(count);
    }

    private async Task OnAlertCountChanged()
    {
        _lowStockCount = Alerts.LatestCount;
        await InvokeAsync(StateHasChanged);
    }

    private async void OnWarehouseChanged()
    {
        // Warehouse changed — poll immediately with new warehouse.
        _timer?.Change(Timeout.Infinite, Timeout.Infinite); // pause
        await PollAlerts();
        _timer?.Change(TimeSpan.FromSeconds(10), TimeSpan.FromSeconds(10)); // resume
        await InvokeAsync(StateHasChanged);
    }

    public void Dispose()
    {
        _timer?.Dispose();
        WarehouseState.OnChange -= OnWarehouseChanged;
        Alerts.OnAlertCountChanged -= OnAlertCountChanged;
    }
}

